function parseAccessTokenFromURL() {
  const hashParams = new URLSearchParams(window.location.hash.substring(1));
  return hashParams.get('access_token');
}

function storeAccessToken(token) {
  sessionStorage.setItem('accessToken', token);
}

function getAccessToken() {
  return sessionStorage.getItem('accessToken');
}

function clearAccessToken() {
  sessionStorage.removeItem('accessToken');
}

async function makeAPICall(endpoint, accessToken) {
  try {
    const response = await fetch(endpoint, {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${accessToken}`
      }
    });
    return await response.json();
  } catch (error) {
    console.error('Error making API call:', error);
    throw error;
  }
}

function handleOAuthResponse() {
  const accessToken = parseAccessTokenFromURL();
  if (accessToken) {
    storeAccessToken(accessToken);
    // Example: Make an API call after successful OAuth
    makeAPICall('/api/userinfo', accessToken).then(data => {
      console.log('User info:', data);
    }).catch(error => {
      console.error('API request failed:', error);
    });
  } else {
    console.error('No access token found in URL');
  }
}

